-- ============================================================
-- STEP 1: Delete old wrong-formula SF Bay tiles
-- ============================================================
DELETE FROM hrc_tiles
WHERE longitude BETWEEN -123.0 AND -121.2
  AND latitude  BETWEEN  37.0  AND  38.6;

-- ============================================================
-- STEP 2: Insert corrected tiles
-- ============================================================
-- ============================================================
-- HRC Index — insert new tiles from: HRC_SFBay_Tiles_updated - HRC_SFBay_Tiles_updated.csv
-- Confidence tier: C (ERA5 reanalysis)
-- restoration_gap left NULL — compute separately once
--   ecoregion reference percentiles are known for these regions
-- ON CONFLICT DO NOTHING — safe to re-run
-- Paste this entire block into Supabase SQL Editor and click Run
-- ============================================================

BEGIN;


COMMIT;

-- 221 INSERT statements generated
-- After running, verify with:
-- SELECT COUNT(*), AVG(hrc_score), AVG(trend_score_60m)
-- FROM hrc_tiles
-- WHERE ecoregion_name IS NOT NULL
-- ORDER BY latitude;

-- NOTE: restoration_gap is NULL for these tiles.
-- To populate it, compute the 90th percentile HRC of protected-area
-- tiles per ecoregion and run an UPDATE pass.
-- ============================================================
-- STEP 3: Recompute restoration_gap for SF Bay ecoregions
-- ============================================================
UPDATE hrc_tiles t
SET restoration_gap = ref.p90 - t.hrc_score
FROM (
  SELECT
    ecoregion_name,
    PERCENTILE_CONT(0.90) WITHIN GROUP (ORDER BY hrc_score) AS p90
  FROM hrc_tiles
  WHERE longitude BETWEEN -123.0 AND -121.2
    AND latitude  BETWEEN  37.0  AND  38.6
    AND ecoregion_name IS NOT NULL
  GROUP BY ecoregion_name
) ref
WHERE t.ecoregion_name = ref.ecoregion_name
  AND t.longitude BETWEEN -123.0 AND -121.2
  AND t.latitude  BETWEEN  37.0  AND  38.6;

-- Verify:
SELECT COUNT(*), ROUND(AVG(hrc_score)::numeric, 2) AS avg_hrc,
       ROUND(AVG(trend_score_60m)::numeric, 2) AS avg_trend,
       ROUND(AVG(restoration_gap)::numeric, 2) AS avg_gap
FROM hrc_tiles
WHERE longitude BETWEEN -123.0 AND -121.2
  AND latitude  BETWEEN  37.0  AND  38.6;
